	m := newTestMatcher()

	uid, ok := m.Match("Harvard")
	if !ok {
		t.Fatal("expected DB alias match for 'Harvard'")
	}
	if uid != "166027" {
		t.Errorf("got unit_id %q, want %q", uid, "166027")
	}
}

