	_, ok := m.Match("Nonexistent University of Nowhere")
	if ok {
		t.Fatal("expected no match for unknown institution")
	}
}

func TestMatcherMatch_ThePrefix(t *testing.T) {
	m := newTestMatcher()

	// "The Ohio State University" normalizes to "ohio state university main campus"
	uid, ok := m.Match("The Ohio State University-Main Campus")
	if !ok {
		t.Fatal("expected match after 'The ' prefix removal")
	}
	if uid != "204796" {
		t.Errorf("got unit_id %q, want %q", uid, "204796")
	}
}

func TestMatcherMatchByOPE6(t *testing.T) {
	m := newTestMatcher()

	uid, ok := m.MatchByOPE6("001082")
	if !ok {
		t.Fatal("expected OPE6 match")
	}
	if uid != "166027" {
		t.Errorf("got unit_id %q, want %q", uid, "166027")
	}

	_, ok = m.MatchByOPE6("999999")
	if ok {
		t.Fatal("expected no OPE6 match for unknown ID")
	}
}

func TestMatcherMatchByOPE8(t *testing.T) {
	m := newTestMatcher()

	uid, ok := m.MatchByOPE8("00108200")
	if !ok {
		t.Fatal("expected OPE8 match")
	}
	if uid != "166027" {
		t.Errorf("got unit_id %q, want %q", uid, "166027")
	}

	_, ok = m.MatchByOPE8("99999999")
	if ok {
		t.Fatal("expected no OPE8 match for unknown ID")
	}
}

func TestMatcherMatch_Purdue_HyphenVariant(t *testing.T) {
	m := newTestMatcher()

	// "Purdue University-Main Campus" normalizes → "purdue university main campus"
	uid, ok := m.Match("Purdue University-Main Campus")
	if !ok {
		t.Fatal("expected normalized match for hyphenated campus name")
	}
	if uid != "243780" {
		t.Errorf("got unit_id %q, want %q", uid, "243780")
	}
}

// TestIntegrationMatcherLoad verifies Load() against a real database.
// Skipped when running with -short or when DATABASE_URL is unset.
func TestIntegrationMatcherLoad(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}
	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		t.Skip("DATABASE_URL not set")
	}

	ctx := context.Background()
	pool, err := dbutil.Connect(ctx, dbURL)
	if err != nil {
		t.Fatalf("namematch: connect: %v", err)
	}
	defer pool.Close()

	m, err := Load(ctx, pool)
	if err != nil {
		t.Fatalf("Load: %v", err)
	}

	// Verify basic stats — we should have loaded something
	if len(m.exact) == 0 {
		t.Error("exact map is empty — no institutions loaded")
	}
	if len(m.ope6) == 0 {
		t.Error("ope6 map is empty")
	}

	// Spot-check a known canonical name if it exists in the DB.
	// Harvard (unit_id 166027) should always be present in NCES data.
	uid, ok := m.Match("Harvard University")
	if ok {
		t.Logf("Harvard University → unit_id %q", uid)
	}

	// Verify OPE lookups are consistent: if we have an exact match,
	// OPE lookups for the same institution should return the same unit_id.
	for ope6, wantUID := range m.ope6 {
		gotUID, found := m.MatchByOPE6(ope6)
		if !found {
			t.Errorf("MatchByOPE6(%q): not found but expected in map", ope6)
		}
		if gotUID != wantUID {
			t.Errorf("MatchByOPE6(%q) = %q, want %q", ope6, gotUID, wantUID)
		}
		// Only spot-check first 5 to keep runtime short
		break
	}
}

