package namematch

import (
	"encoding/json"
	"math"
	"os"
	"sort"
)

// Candidate represents an institution available for fuzzy matching.
type Candidate struct {
	Name   string
	UnitID string
	State  string
}

// FuzzyResult pairs a candidate with its similarity score.
type FuzzyResult struct {
	Candidate
	Score float64
}

// UnmatchedEntry records a name that could not be matched deterministically,
// along with the best fuzzy candidates found.
type UnmatchedEntry struct {
	Name          string        `json:"name"`
	StateHint     string        `json:"state_hint,omitempty"`
	TopCandidates []FuzzyResult `json:"top_candidates"`
}

// FuzzyMatcher performs Jaro-Winkler fuzzy matching against a set of
// institution candidates. Candidates are indexed by state for efficient
// filtering when a state hint is available.
type FuzzyMatcher struct {
	all     []indexedCandidate
	byState map[string][]indexedCandidate
}

// indexedCandidate stores a candidate alongside its pre-normalized name.
type indexedCandidate struct {
	Candidate
	normalized string
}

// DefaultThreshold is the minimum Jaro-Winkler score for a match.
const DefaultThreshold = 0.92

// maxResults is the maximum number of candidates returned by Match.
const maxResults = 5

// NewFuzzyMatcher builds a FuzzyMatcher from the given candidates. Each
// candidate's name is pre-normalized for efficient repeated comparisons.
func NewFuzzyMatcher(candidates []Candidate) *FuzzyMatcher {
	fm := &FuzzyMatcher{
		all:     make([]indexedCandidate, len(candidates)),
		byState: make(map[string][]indexedCandidate),
	}
	for i, c := range candidates {
		ic := indexedCandidate{
			Candidate:  c,
			normalized: Normalize(c.Name),
		}
		fm.all[i] = ic
		if c.State != "" {
			fm.byState[c.State] = append(fm.byState[c.State], ic)
		}
	}
	return fm
}

// Match returns the top candidates whose Jaro-Winkler similarity to name
// exceeds DefaultThreshold, sorted by score descending. When stateHint is
// non-empty, only candidates in that state are considered.
func (fm *FuzzyMatcher) Match(name string, stateHint string) []FuzzyResult {
	norm := Normalize(name)

	candidates := fm.all
	if stateHint != "" {
		if sc, ok := fm.byState[stateHint]; ok {
			candidates = sc
		} else {
			return nil
		}
	}

	var results []FuzzyResult
	for _, c := range candidates {
		score := jaroWinkler(norm, c.normalized)
		if score >= DefaultThreshold {
			results = append(results, FuzzyResult{
				Candidate: c.Candidate,
				Score:     score,
			})
		}
	}

	sort.Slice(results, func(i, j int) bool {
		return results[i].Score > results[j].Score
	})

	if len(results) > maxResults {
		results = results[:maxResults]
	}
	return results
}

// WriteReport writes a JSON report of unmatched entries to the given path.
func WriteReport(path string, unmatched []UnmatchedEntry) error {
	data, err := json.MarshalIndent(unmatched, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(path, data, 0o644)
}

// jaroWinkler computes the Jaro-Winkler similarity between two strings.
// Returns a value in [0, 1] where 1 means identical.
func jaroWinkler(s1, s2 string) float64 {
	j := jaro(s1, s2)
	if j == 0 {
		return 0
	}

	// Winkler prefix bonus: up to 4 characters, scaling factor 0.1
	prefix := 0
	limit := 4
	if len(s1) < limit {
		limit = len(s1)
	}
	if len(s2) < limit {
		limit = len(s2)
	}
	for i := 0; i < limit; i++ {
		if s1[i] == s2[i] {
			prefix++
		} else {
			break
		}
	}

	return j + float64(prefix)*0.1*(1-j)
}

// jaro computes the Jaro similarity between two strings.
func jaro(s1, s2 string) float64 {
	if s1 == s2 {
		return 1
	}
	l1, l2 := len(s1), len(s2)
	if l1 == 0 || l2 == 0 {
		return 0
	}

	// Match window: floor(max(|s1|,|s2|)/2) - 1
	maxLen := l1
	if l2 > maxLen {
		maxLen = l2
	}
	window := int(math.Floor(float64(maxLen)/2)) - 1
	if window < 0 {
		window = 0
	}

	s1Matches := make([]bool, l1)
	s2Matches := make([]bool, l2)

	matches := 0
	transpositions := 0

	for i := 0; i < l1; i++ {
		lo := i - window
		if lo < 0 {
			lo = 0
		}
		hi := i + window + 1
		if hi > l2 {
			hi = l2
		}
		for j := lo; j < hi; j++ {
			if s2Matches[j] || s1[i] != s2[j] {
				continue
			}
			s1Matches[i] = true
			s2Matches[j] = true
			matches++
			break
		}
	}

	if matches == 0 {
		return 0
	}

	k := 0
	for i := 0; i < l1; i++ {
		if !s1Matches[i] {
			continue
		}
		for !s2Matches[k] {
			k++
		}
		if s1[i] != s2[k] {
			transpositions++
		}
		k++
	}

	m := float64(matches)
	return (m/float64(l1) + m/float64(l2) + (m-float64(transpositions)/2)/m) / 3
}

